-- Seed data for BudgetBite meals database
-- This file contains sample meals to populate the database

-- 1. Apple Cake
INSERT OR REPLACE INTO meals (id, name, category, instructions, ingredients, thumbnail)
VALUES ('53380', 'apple cake', 'Dessert', 'Preheat the oven to 180°C. Grease a cake pan and line it with baking paper. In a large bowl, break the four eggs with the sugar and beat until they have tripled in volume and become fluffy. Sift the self-rising baking flour and add it to your egg mixture. Fold this over, preserving as much air as possible. Add the melted (and slightly cooled) butter and mix until combined. Add cinnamon, pinch of salt and vanilla extract. Add the diced apple to the batter and gently fold them into the batter. Pour the batter into the prepared cake pan and smooth the top. Bake for about 45-50 minutes.', '4 Eggs, 200g Sugar, 200g Self-raising Flour, 200g Melted Butter, 1 tsp Vanilla Extract, 1 tsp Ground Cinnamon, 3 Apples, Pinch Salt, Sprinkling Ground Sugar', 'https://www.themealdb.com/images/media/meals/c0gmo31766594751.jpg');

-- 2. Arrabiata
INSERT OR REPLACE INTO meals (id, name, category, instructions, ingredients, thumbnail)
VALUES ('52977', 'arrabiata', 'Pasta', '1. Cook pasta in salted boiling water until al dente. 2. While pasta cooks, finely chop garlic and red chili peppers. 3. Heat olive oil in a large skillet over medium heat. 4. Add garlic and chili peppers to the oil and fry for a few minutes until fragrant. 5. Add tomatoes and simmer for about 10 minutes. 6. Drain pasta and add to the tomato sauce. 7. Toss well to combine. 8. Serve immediately with grated Pecorino Romano cheese.', '400g spaghetti, 400g canned tomatoes, 3 cloves garlic, 2 red chili peppers, 100ml olive oil, Salt and pepper to taste, Pecorino Romano cheese for serving', 'https://www.themealdb.com/images/media/meals/b6rrjq1508773722.jpg');

-- 3. Baklava
INSERT OR REPLACE INTO meals (id, name, category, instructions, ingredients, thumbnail)
VALUES ('53279', 'baklava with spiced nuts, ricotta & chocolate', 'Dessert', 'Step 1: Make the syrup. Tip the sugar into a large saucepan with 650ml water. Simmer for 15 mins. Step 2: For the filling, crush all of the nuts in a pestle and mortar. Stir through spices. Step 3: Mix ricotta with zests and vanilla. Brush tray with butter. Layer filo sheets, nut mixture, and ricotta. Roll and scrunch. Step 4: Bake for 20-25 mins until golden. Pour over syrup. Step 5: Drizzle with melted dark chocolate and pistachios.', '500g Sugar, Lemon Juice, 300g Walnuts, 200g Pecan Nuts, 100g Almonds, 2 tbsp Cinnamon, 1 tbsp Cardomom, 500g Ricotta, Zest of Lemon/Orange, 1 tbsp Vanilla Bean Paste, 250g Butter, 500g Filo Pastry, 100g Pistachios', 'https://www.themealdb.com/images/media/meals/ytme8t1764111401.jpg');

-- 4. Big Mac
INSERT OR REPLACE INTO meals (id, name, category, instructions, ingredients, thumbnail)
VALUES ('53013', 'big mac', 'Beef', '1. For the sauce, combine all ingredients in a bowl and chill. 2. Season the mince and form into 4 balls. Flatten into four 15cm circles. Cook patties for 1-2 mins each side. 3. Slice each burger bun into three acrossways and toast. 4. To assemble, spread sauce on bottom base. Top with onion, lettuce, cheese, patty, and pickles. Repeat for middle layer. Top with lid.', '400g Minced Beef, 2 tbs Olive Oil, 2 Sesame Seed Burger Buns, Chopped Onion, 1/4 Iceberg Lettuce, 2 sliced Cheese, 2 large Dill Pickles, 1 cup Mayonnaise, White Wine Vinegar, Mustard, Onion Salt, Garlic Powder, Paprika', 'https://www.themealdb.com/images/media/meals/urzj1d1587670726.jpg');

-- 5. Breakfast Potatoes
INSERT OR REPLACE INTO meals (id, name, category, instructions, ingredients, thumbnail)
VALUES ('52844', 'breakfast potatoes', 'Breakfast', '1. Dice potatoes into small cubes. 2. Heat olive oil in a large skillet. 3. Add diced onions and bell peppers, sauté for 3-4 minutes. 4. Add potato cubes and cook for 10-12 minutes until golden and crispy. 5. Season with salt, pepper, and paprika. 6. Add garlic and cook for 1 minute more. 7. Serve hot, optionally topped with fried eggs and fresh herbs.', '4 medium potatoes, 1 red bell pepper, 1 onion, 3 cloves garlic, 2 tbsp olive oil, Salt and pepper to taste, 1 tsp paprika, Fresh herbs', 'https://www.themealdb.com/images/media/meals/1550441882.jpg');

-- 6. Cajun Spiced Fish Tacos
INSERT OR REPLACE INTO meals (id, name, category, instructions, ingredients, thumbnail)
VALUES ('52819', 'cajun spiced fish tacos', 'Seafood', 'Mix cajun spice and cayenne with seasoning to coat fish. Heat oil in a frying pan and cook fish over medium heat until golden. Prepare dressing by combining ingredients. Soften tortillas in microwave. Pile high with avocado, lettuce, spring onion, salsa, and fish. Drizzle over dressing.', '2 tbsp cajun, 1 tsp cayenne pepper, 4 fillets white fish, 1 tsp vegetable oil, 8 flour tortilla, 1 avocado, 2 lettuce, 4 Spring Onions, 300ml salsa, 1 pot sour cream, 1 lemon, 1 clove garlic', 'https://www.themealdb.com/images/media/meals/uvuyxu1503067369.jpg');

-- 7. Carrot Cake
INSERT OR REPLACE INTO meals (id, name, category, instructions, ingredients, thumbnail)
VALUES ('52897', 'carrot cake', 'Dessert', 'Preheat oven to 160C. Grease a 26cm tin. Mix all ingredients except carrots and walnuts together until well combined. Stir in carrots and walnuts. Spoon into tin and bake for 1 hour 15 minutes. Cool. For icing, beat cream cheese, sugar, and butter together until fluffy. Spread over top of cake.', '450ml Vegetable Oil, 400g Plain Flour, 2 tsp Bicarbonate Of Soda, 550ml Sugar, 5 Eggs, 1/2 tsp Salt, 2 tsp Cinnamon, 500g grated Carrots, 150g Walnuts, 200g Cream Cheese, 150g Caster Sugar, 100g Butter', 'https://www.themealdb.com/images/media/meals/vrspxv1511722107.jpg');

-- 8. Cassava Pizza
INSERT OR REPLACE INTO meals (id, name, category, instructions, ingredients, thumbnail)
VALUES ('53330', 'cassava pizza', 'Pork', 'Preheat the oven to 200ºC. Cut the bacon or chorizo into medium pieces and the paprika into strips. Spread a little tomato sauce and mozzarella cheese on each portion of cassava. Add the meat, corn, turkey ham, olives and paprika. Bake for 7 to 10 minutes.', '6 thick slices Casabe, 450g Tomato Sauce, 225g Chorizo, 225g Turkey Ham, 75g Sweetcorn, 40g Green Olives, 55g Paprika, 50g Mozzarella', 'https://www.themealdb.com/images/media/meals/lrfdwz1764438393.jpg');

-- 9. Cheese Borek
INSERT OR REPLACE INTO meals (id, name, category, instructions, ingredients, thumbnail)
VALUES ('53290', 'cheese borek', 'Side', 'Whisk together egg, parsley, garlic and red pepper. Mix in Gouda and Emmentaler. Place phyllo sheet on flat surface and brush with butter. Cut into 4 strips. Place teaspoon of filling at one end and fold into triangular folds. Bake at 350F for 30 minutes until browned.', '1 beaten Egg, 1 bunch Parsley, 2 cloves minced Garlic, 3/4 tsp Red Pepper, 6 oz Gouda, 6 oz Emmentaler, 12 Phyllo Dough, 1 1/2 cups Unsalted Butter', 'https://www.themealdb.com/images/media/meals/oal8x31764119345.jpg');

-- 10. Chicken Handi
INSERT OR REPLACE INTO meals (id, name, category, instructions, ingredients, thumbnail)
VALUES ('52795', 'chicken handi', 'Chicken', 'Heat oil in a large pot. Fry onion until golden brown and set aside. Sautè garlic and tomatoes until soft. Return onion to pot. Add ginger paste, cumin, coriander seeds, and green chillies. Add turmeric and chilli powder. Add chicken and cook covered for 15 mins. Add yogurt, remaining coriander, fenugreek, and cream. Serve hot.', '1.2 kg Chicken, 5 Onion, 2 Tomatoes, 8 cloves Garlic, 1 tbsp Ginger paste, 1/4 cup Vegetable oil, Cumin, Coriander, Turmeric, Chilli powder, 2 Green chilli, 1 cup Yogurt, 3/4 cup Cream, Fenugreek, Garam masala', 'https://www.themealdb.com/images/media/meals/wyxwsp1486979827.jpg');

-- 11. Chivito Sandwich
INSERT OR REPLACE INTO meals (id, name, category, instructions, ingredients, thumbnail)
VALUES ('53319', 'chivito sandwich', 'Beef', 'Bake brioche buns. Grill sirloin steaks, bacon, and ham. Fry eggs. Toast buns. Spread mustard, layer steak, ham, cheese, bacon, tomato, and lettuce. Top with fried egg and chimichurri.', '80g Milk, 60g Butter, 1 tbsp Molasses, 220g Water, 500g Bread Flour, 8 Sirloin steak, 8 Bacon, 8 slices Ham, 8 slices Mozzarella, 4 Tomato, Lettuce, Mustard, Chimichurri sauce', 'https://www.themealdb.com/images/media/meals/j80gmw1764372176.jpg');

-- 12. Chocolate Chip Cookies
INSERT OR REPLACE INTO meals (id, name, category, instructions, ingredients, thumbnail)
VALUES ('52855', 'chocolate chip cookies', 'Dessert', '1. Preheat oven to 375°F. 2. Cream together butter and sugars. 3. Beat in eggs and vanilla. 4. Combine dry ingredients and blend into butter mixture. 6. Stir in chocolate chips. 7. Drop rounded tablespoons onto sheets. 8. Bake for 9-11 minutes.', '225g butter, 200g brown sugar, 100g white sugar, 2 eggs, 2 tsp vanilla extract, 280g flour, 1 tsp baking soda, 1 tsp salt, 340g chocolate chips', 'https://www.themealdb.com/images/media/meals/sxxpqt1511590270.jpg');

-- 13. Chocolate Gateau
INSERT OR REPLACE INTO meals (id, name, category, instructions, ingredients, thumbnail)
VALUES ('52776', 'chocolate gateau', 'Dessert', 'Preheat oven to 180C. Melt chocolate in heatproof bowl. Cream butter and sugar until light and fluffy. Beat in eggs and flour. Fold in melted chocolate and milk. Bake for 50-55 mins.', '250g Plain chocolate, 175g Butter, 2 tbsp Milk, 5 Eggs, 175g Granulated Sugar, 125g Flour', 'https://www.themealdb.com/images/media/meals/tqtywx1468317395.jpg');

-- 14. Eggplant Adobo
INSERT OR REPLACE INTO meals (id, name, category, instructions, ingredients, thumbnail)
VALUES ('53073', 'eggplant adobo', 'Vegetarian', 'Slice eggplant into quarters and coat with sugar and salt. Fry garlic until crisp. Brown pork. Cook eggplant until browned. Add water, garlic, vinegar, soy sauce, bay leaves, and simmer until tender.', '1 lb Egg Plants, 2 tbs Sugar, 1 tsp Salt, 1 tsp Pepper, 1 whole Garlic, 3 tbs Olive Oil, 4 oz Ground Pork, 3 tbs Rice Vinegar, 2 tbs Soy Sauce, 2 Bay Leaf', 'https://www.themealdb.com/images/media/meals/y7h0lq1683208991.jpg');

-- 15. Fish Pie
INSERT OR REPLACE INTO meals (id, name, category, instructions, ingredients, thumbnail)
VALUES ('52802', 'fish pie', 'Seafood', 'Boil potatoes and mash with olive oil. Poach fish in milk. Make a white sauce with milk and flour. Stir in cream. Mix fish, prawns, artichokes, leeks, and herbs into sauce. Top with mash and Gruyere. Bake for 35-40 mins.', '900g Floury Potatoes, 2 tbsp Olive Oil, 600ml Milk, 800g White Fish, 1 tbsp Plain flour, Nutmeg, 3 tbsp Double Cream, 200g Artichokes, 1 Leek, 200g Prawns, Parsley, Dill, Lemon, 25g Gruyere', 'https://www.themealdb.com/images/media/meals/ysxwuq1487323065.jpg');

-- 16. Grilled Eggplant with Coconut Milk
INSERT OR REPLACE INTO meals (id, name, category, instructions, ingredients, thumbnail)
VALUES ('53074', 'grilled eggplant with coconut milk', 'Vegetarian', 'Prick eggplants with fork. Grill until skins are dark and soft. Peel skin. In a bowl, mix coconut milk, lemon juice, salt, and pepper flakes. Pour mixture over eggplant and top with green onions.', '6 Egg Plants, 1 can Coconut Milk, 1 tbs Lemon Juice, 1 tsp Salt, Red Pepper Flakes, 4 Sticks Onions', 'https://www.themealdb.com/images/media/meals/bopa2i1683209167.jpg');

-- 17. Grilled Fish with Lemon
INSERT OR REPLACE INTO meals (id, name, category, instructions, ingredients, thumbnail)
VALUES ('53050', 'grilled fish with lemon', 'Seafood', '1. Preheat grill to medium-high heat. 2. Pat fish dry and season inside and out with salt and pepper. 3. Stuff cavity with lemon slices and herbs. 4. Brush with olive oil. 5. Grill for 4-5 minutes per side until flesh flakes easily.', '2 whole fish (1kg), 30ml olive oil, 2 lemons, Fresh herbs, Salt and pepper to taste, Lemon wedges for serving', 'https://www.themealdb.com/images/media/meals/lfrtxb1562637546.jpg');

-- 18. Grilled Portuguese Sardines
INSERT OR REPLACE INTO meals (id, name, category, instructions, ingredients, thumbnail)
VALUES ('53041', 'grilled portuguese sardines', 'Seafood', 'Mix marinade ingredients. Toss sardines in bowl and chill for few hours. Heat grill and cook sardines for 4-5 mins each side until caramelised. Drizzle with oil and squeeze over lemon.', '8 Sardines, 2 tbs Olive Oil, 3 cloves Garlic, 1 tbs Paprika, 1/2 Lemon, 4 sprigs Rosemary, 1 Red Chilli', 'https://www.themealdb.com/images/media/meals/lpd4wy1614347943.jpg');

-- 19. Jam Jam Cookies
INSERT OR REPLACE INTO meals (id, name, category, instructions, ingredients, thumbnail)
VALUES ('53339', 'jam jam cookies', 'Dessert', 'Preheat oven to 350F. Cream butter, sugar, and egg. Add molasses and vanilla. Mix dry ingredients and blend into wet ingredients. Shape dough into discs. Bake for 10-12 mins. Cool and sandwich with jam.', '1 Egg, 1 cup Butter, 1 cup Sugar, 1/2 cup Molasses, 1 tsp Vanilla, 4 cups Flour, 2 cups Jam', 'https://www.themealdb.com/images/media/meals/sktequ1764447186.jpg');

-- 20. Kofta Burgers
INSERT OR REPLACE INTO meals (id, name, category, instructions, ingredients, thumbnail)
VALUES ('53257', 'kofta burgers', 'Lamb', 'Mix lamb mince with spices and salt. Roll into 16 small burgers. Grill on high setting for 5-6 mins each side until cooked through. Serve in pita bread with accompaniment.', '1kg Lamb, 2 Onion, 1 Garlic Bulb, 6 tablespoons Garam Masala, Bunch Coriander, 1 tablespoon Chilli Sauce, 8 Pita Bread, 4 sliced Tomato, Red Cabbage, Red Onions, Yogurt', 'https://www.themealdb.com/images/media/meals/lgmnff1763789847.jpg');